(function(){
  var DM_KEY = 'dm'; // same key darkmode.min.js uses — null means "no explicit choice"

  // One emoji per period — the literal "sun moving across the sky" cue
  // next to the logo/avatar, independent of (and more immediately
  // legible than) the sidebar gradient shift below.
  var SUN_EMOJI = {
    morning:   '🌅', // 🌅 sunrise
    afternoon: '☀️', // ☀️ full shine
    evening:   '🌇', // 🌇 sunset
    night:     '🌙', // 🌙 night
  };

  function periodFor(hour) {
    if (hour >= 6 && hour < 12) return 'morning';
    if (hour >= 12 && hour < 17) return 'afternoon';
    if (hour >= 17 && hour < 21) return 'evening';
    return 'night';
  }

  function updateSunIndicator(period, hidden) {
    var el = document.getElementById('sun-indicator');
    if (!el) return;
    el.textContent = hidden ? '' : (SUN_EMOJI[period] || '');
  }

  function apply() {
    if (localStorage.getItem(DM_KEY) !== null) {
      // User has explicitly picked light or dark via the dark-mode toggle —
      // that choice wins outright, time-based theming stays off.
      document.body.removeAttribute('data-time-theme');
      updateSunIndicator(null, true);
      return;
    }
    var period = periodFor(new Date().getHours());
    updateSunIndicator(period, false);
    if (period === 'afternoon') {
      // Afternoon IS the existing default palette — no attribute needed.
      document.body.removeAttribute('data-time-theme');
    } else {
      document.body.setAttribute('data-time-theme', period);
    }
  }

  document.addEventListener('DOMContentLoaded', function() {
    apply();
    // Re-check right after any dark-mode toggle click, deferred so
    // darkmode.min.js's own click handler (which writes localStorage) has
    // already run by the time this reads it.
    document.querySelectorAll('.dm-toggle').forEach(function(btn) {
      btn.addEventListener('click', function() { setTimeout(apply, 0); });
    });
  });

  setInterval(apply, 5 * 60 * 1000); // catches a page left open across a period boundary
})();
